import { type MutableRefObject, useCallback } from 'react';

export type RefItem<T> = ((element: T | null) => void) | MutableRefObject<T | null> | null | undefined;

export const useCombinedRef = <T>(...refs: Array<RefItem<T>>): ((element: T | null) => void) => {
	const refCb = useCallback(
		(element: T | null) => {
			for (const ref of refs) {
				if (!ref) {
					continue;
				}

				if (typeof ref === 'function') {
					ref(element);
				} else {
					ref.current = element;
				}
			}
		},
		[refs],
	);

	return refCb;
};
